const queue = $('Split Queue Items').first().json;
const promptRow = ($('Get Active Prompt').first().json?.[0]) || $('Get Active Prompt').first().json;
const historyResp = $('Get History').first().json;
const ctxArr = $('Get Lead Context').first().json;
const plansResp = $('Get Plans (Tool)').first().json;

const history = Array.isArray(historyResp) ? historyResp : (historyResp?.data || []);
const leadCtxRow = Array.isArray(ctxArr) ? (ctxArr[0] || {}) : ctxArr;
const leadContext = leadCtxRow?.lead_context || {};
const stage = leadCtxRow?.conversation_stage || 'new';
const decisionMaker = leadCtxRow?.decision_maker_name || queue.metadata?.pushName || '';
const receivedAt = queue.metadata?.received_at || queue.scheduled_for;

const systemPrompt = promptRow?.system_prompt || 'Você é Ana do Sondar+.';
const modelPrimary = promptRow?.model_primary || 'gemini-2.0-flash';
const temperature = promptRow?.temperature || 0.4;
const maxTokens = promptRow?.max_tokens || 500;

const historyChronological = history.slice().reverse();
const contextLines = historyChronological.map(m => {
  const role = m.direction === 'outbound' ? 'Ana' : (decisionMaker || 'Cliente');
  return role + ': ' + m.content;
}).join('\n');

const leadBrief = [
  decisionMaker ? 'Nome: ' + decisionMaker : null,
  leadCtxRow?.company_name ? 'Empresa: ' + leadCtxRow.company_name : null,
  leadCtxRow?.city ? 'Cidade: ' + leadCtxRow.city : null,
  'Stage: ' + stage,
  leadContext.pain_points?.length ? 'Dores detectadas: ' + leadContext.pain_points.join('; ') : null,
  leadContext.objections?.length ? 'Objeções: ' + leadContext.objections.join('; ') : null,
  leadContext.signals ? 'Sinais: ' + JSON.stringify(leadContext.signals) : null,
  leadContext.last_summary ? 'Resumo: ' + leadContext.last_summary : null
].filter(Boolean).join('\n');

let planosTxt = '';
try {
  const plans = plansResp?.planos || [];
  planosTxt = plans.map(p => {
    const limits = p.ilimitado ? 'ilimitado' : [p.max_obras ? p.max_obras + ' obras' : null, p.max_furos ? p.max_furos + ' furos' : null, p.max_usuarios ? p.max_usuarios + ' usuários' : null].filter(Boolean).join(' / ');
    return '- ' + p.nome + ' (R$' + p.preco_brl + '): ' + limits;
  }).join('\n');
} catch(e) {}

// Formato de hora amigável pra explicar o delay
const receivedDate = new Date(receivedAt);
const agora = new Date();
const diffMs = agora - receivedDate;
const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
let delayTxt = '';
if (diffHours < 12) delayTxt = 'ontem à noite';
else if (diffHours < 24) delayTxt = 'ontem';
else if (diffHours < 48) delayTxt = 'anteontem';
else delayTxt = 'no fim de semana';

const userMessage = 'CONTEXTO ESPECIAL: ' + (decisionMaker || 'O cliente') + ' escreveu ' + delayTxt + ', fora do horário comercial. Agora é segunda/dia útil 9h e você está respondendo pela 1ª vez.\n\nA mensagem que ele mandou foi:\n"' + queue.content + '"\n\nINSTRUÇÕES:\n1. Cumprimente mencionando que viu a msg dele\n2. Responda o que ele perguntou usando o contexto\n3. Seja natural, tipo "Oi João, bom dia! Vi sua msg de ' + delayTxt + '. Sobre o que você perguntou..."';

const parts = [];
if (leadBrief) parts.push('PERFIL DO LEAD:\n' + leadBrief);
if (planosTxt) parts.push('PLANOS ATIVOS (fonte oficial):\n' + planosTxt);
if (contextLines) parts.push('HISTÓRICO RECENTE:\n' + contextLines);
parts.push(userMessage);
const fullContext = parts.join('\n\n---\n\n');

return [{json: {
  queue_id: queue.id,
  phone: queue.phone,
  pushName: decisionMaker,
  lead_id: queue.lead_id,
  system_prompt: systemPrompt,
  user_message: fullContext,
  model: modelPrimary,
  temperature,
  max_tokens: maxTokens
}}];

const geminiResp = $input.first().json;
const inbound = $('Build Wake-up Prompt').first().json;

let aiText = '';
try { aiText = geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text || ''; } catch(e) {}

let escalation = null;
const escMatch = aiText.match(/<<ESCALAR:([a-z_]+):([^>]+)>>/i);
if (escMatch) {
  escalation = { reason: escMatch[1].toLowerCase(), summary: escMatch[2].trim() };
  aiText = aiText.replace(escMatch[0], '').trim();
}

aiText = aiText.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
aiText = aiText.replace(/<\/?final>/gi, '').trim();
aiText = aiText.replace(/^Ana:\s*/i, '').trim();
aiText = aiText.replace(/```[\s\S]*?```/g, '').trim();

if (!aiText) aiText = 'Oi! Vi sua mensagem. Vou já te responder, só um momento.';

const textLen = aiText.length;
const delay_ms = Math.min(Math.max(textLen * 60 + 1200, 3000), 15000);

return [{json: {
  queue_id: inbound.queue_id,
  phone: inbound.phone,
  lead_id: inbound.lead_id,
  ai_text: aiText,
  delay_seconds: Math.floor(delay_ms / 1000),
  escalation_reason: escalation?.reason || null,
  escalation_summary: escalation?.summary || null,
  should_escalate: escalation !== null
}}];

